1	const PROCESSING_FEE = 5;
2	const BASE_PREMIUM: Record<string, number> = {
3	  sword: 100,
4	  amulet: 60,
5	  staff: 80,
6	  potion: 40,
7	  rune: 25,
8	  moonstone: 25,
9	};
10	
11	type Item = {
12	  type: string;
13	  material?: string;
14	  enchantment?: number;
15	  cursed?: boolean;
16	};
17	type QuoteStep = { op: "quote"; items: Item[] };
18	type Damage = { itemType: string; amount: number };
19	type ClaimStep = {
20	  op: "claim";
21	  policy: number;
22	  incident: { cause: string; damages: Damage[] };
23	};
24	type Step = QuoteStep | ClaimStep;
25	type Customer = { yearsWithMHPCO: number };
26	type Scenario = { customer: Customer; steps: Step[] };
27	
28	const basePremiumFor = (type: string): number => BASE_PREMIUM[type] ?? 0;
29	
30	// An item's insurance value is always 10× its base premium.
31	const INSURANCE_VALUE_MULTIPLIER = 10;
32	
33	const insuranceValueFor = (type: string): number =>
34	  basePremiumFor(type) * INSURANCE_VALUE_MULTIPLIER;
35	
36	const DEDUCTIBLE = 100;
37	const CAP_MULTIPLIER = 2;
38	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
39	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
40	
41	const FIRST_INSURANCE_RATE = 0.1;
42	
43	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
44	const BLOCK_SIZE = 3;
45	const BLOCK_BASE_PREMIUM = 60;
46	
47	const countBy = <T>(items: T[], keyOf: (item: T) => string): Map<string, number> => {
48	  const counts = new Map<string, number>();
49	  for (const item of items) {
50	    const key = keyOf(item);
51	    counts.set(key, (counts.get(key) ?? 0) + 1);
52	  }
53	  return counts;
54	};
55	
56	const countByType = (items: Item[]): Map<string, number> =>
57	  countBy(items, (item) => item.type);
58	
59	const groupBase = (type: string, count: number): number =>
60	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE
61	    ? BLOCK_BASE_PREMIUM
62	    : count * basePremiumFor(type);
63	
64	const policyBase = (items: Item[]): number =>
65	  Array.from(countByType(items)).reduce(
66	    (total, [type, count]) => total + groupBase(type, count),
67	    0,
68	  );
69	
70	const LOYALTY_RATE = 0.2;
71	const LOYALTY_THRESHOLD_YEARS = 2;
72	const FOLLOW_UP_RATE = 0.15;
73	
74	type PolicyContext = { customer: Customer; isFollowUp: boolean };
75	
76	type PolicyModifier = {
77	  applies: (ctx: PolicyContext) => boolean;
78	  rate: number;
79	  sign: 1 | -1;
80	};
81	
82	const POLICY_MODIFIERS: PolicyModifier[] = [
83	  { applies: () => true, rate: FIRST_INSURANCE_RATE, sign: +1 },
84	  {
85	    applies: (ctx) => ctx.customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS,
86	    rate: LOYALTY_RATE,
87	    sign: -1,
88	  },
89	  { applies: (ctx) => ctx.isFollowUp, rate: FOLLOW_UP_RATE, sign: -1 },
90	];
91	
92	const policyAdjustments = (base: number, ctx: PolicyContext): number =>
93	  POLICY_MODIFIERS.reduce(
94	    (total, mod) => total + (mod.applies(ctx) ? mod.sign * base * mod.rate : 0),
95	    0,
96	  );
97	
98	const CURSE_RATE = 0.5;
99	const HIGH_ENCHANTMENT_RATE = 0.3;
100	const HIGH_ENCHANTMENT_THRESHOLD = 5;
101	
102	const enchantmentLevel = (item: Item | undefined): number =>
103	  item?.enchantment ?? 0;
104	
105	const surchargeWhen = (item: Item, applies: boolean, rate: number): number =>
106	  applies ? basePremiumFor(item.type) * rate : 0;
107	
108	const curseSurcharge = (item: Item): number =>
109	  surchargeWhen(item, item.cursed === true, CURSE_RATE);
110	
111	const highEnchantmentSurcharge = (item: Item): number =>
112	  surchargeWhen(
113	    item,
114	    enchantmentLevel(item) >= HIGH_ENCHANTMENT_THRESHOLD,
115	    HIGH_ENCHANTMENT_RATE,
116	  );
117	
118	const itemSurcharges = (items: Item[]): number =>
119	  items.reduce(
120	    (sum, item) => sum + curseSurcharge(item) + highEnchantmentSurcharge(item),
121	    0,
122	  );
123	
124	// MHPCO always rounds money in its own favor: premiums up, payouts down.
125	const roundPremiumInFavorOfMHPCO = Math.ceil;
126	const roundPayoutInFavorOfMHPCO = Math.floor;
127	
128	const quotePremium = (items: Item[], ctx: PolicyContext): number => {
129	  const base = policyBase(items);
130	  return roundPremiumInFavorOfMHPCO(
131	    base + itemSurcharges(items) + policyAdjustments(base, ctx) + PROCESSING_FEE,
132	  );
133	};
134	
135	const insuranceSum = (items: Item[]): number =>
136	  items.reduce((sum, item) => sum + insuranceValueFor(item.type), 0);
137	
138	const capFor = (items: Item[]): number => CAP_MULTIPLIER * insuranceSum(items);
139	
140	const reimbursableAmount = (amount: number, item: Item | undefined): number => {
141	  const isHighEnchantment =
142	    enchantmentLevel(item) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD;
143	  return isHighEnchantment ? amount * HIGH_ENCHANTMENT_PAYOUT_RATE : amount;
144	};
145	
146	const damagePayout = (damage: Damage, item: Item | undefined): number =>
147	  reimbursableAmount(damage.amount, item) - DEDUCTIBLE;
148	
149	const itemByType = (items: Item[], type: string): Item | undefined =>
150	  items.find((item) => item.type === type);
151	
152	const totalPayout = (damages: Damage[], items: Item[]): number =>
153	  damages.reduce(
154	    (sum, damage) => sum + damagePayout(damage, itemByType(items, damage.itemType)),
155	    0,
156	  );
157	
158	type QuoteResult = { premium: number };
159	type ClaimResult = { payout: number; remainingCap: number };
160	type StepResult = QuoteResult | ClaimResult;
161	type ScenarioResult = { results: StepResult[] };
162	
163	type PolicyLedger = {
164	  registerQuote: (index: number, items: Item[]) => void;
165	  isFollowUp: () => boolean;
166	  itemsFor: (policy: number) => Item[];
167	  recordClaim: (policy: number, desiredPayout: number) => ClaimResult;
168	};
169	
170	const createPolicyLedger = (): PolicyLedger => {
171	  const remainingCaps = new Map<number, number>();
172	  const policyItems = new Map<number, Item[]>();
173	  return {
174	    registerQuote: (index, items) => {
175	      remainingCaps.set(index, capFor(items));
176	      policyItems.set(index, items);
177	    },
178	    isFollowUp: () => remainingCaps.size > 0,
179	    itemsFor: (policy) => policyItems.get(policy) ?? [],
180	    recordClaim: (policy, desiredPayout) => {
181	      const cap = remainingCaps.get(policy) ?? 0;
182	      const payout = Math.min(desiredPayout, cap);
183	      const remainingCap = cap - payout;
184	      remainingCaps.set(policy, remainingCap);
185	      return { payout, remainingCap };
186	    },
187	  };
188	};
189	
190	const handleQuote = (
191	  step: QuoteStep,
192	  index: number,
193	  customer: Customer,
194	  ledger: PolicyLedger,
195	): QuoteResult => {
196	  const ctx: PolicyContext = { customer, isFollowUp: ledger.isFollowUp() };
197	  ledger.registerQuote(index, step.items);
198	  return { premium: quotePremium(step.items, ctx) };
199	};
200	
201	const handleClaim = (step: ClaimStep, ledger: PolicyLedger): ClaimResult => {
202	  const items = ledger.itemsFor(step.policy);
203	  const desired = totalPayout(step.incident.damages, items);
204	  return ledger.recordClaim(step.policy, roundPayoutInFavorOfMHPCO(desired));
205	};
206	
207	const quoteSteps = (steps: Step[]): QuoteStep[] =>
208	  steps.filter((step): step is QuoteStep => step.op === "quote");
209	
210	const claimSteps = (steps: Step[]): ClaimStep[] =>
211	  steps.filter((step): step is ClaimStep => step.op === "claim");
212	
213	const policyQuoteFor = (
214	  steps: Step[],
215	  claim: ClaimStep,
216	): QuoteStep | undefined => {
217	  const referenced = steps[claim.policy];
218	  return referenced?.op === "quote" ? referenced : undefined;
219	};
220	
221	const assertKnownItemTypes = (steps: Step[]): void => {
222	  for (const quote of quoteSteps(steps)) {
223	    for (const item of quote.items) {
224	      if (!(item.type in BASE_PREMIUM)) {
225	        throw new Error(`unknown item type: ${item.type}`);
226	      }
227	    }
228	  }
229	};
230	
231	const countDamagesByType = (damages: Damage[]): Map<string, number> =>
232	  countBy(damages, (damage) => damage.itemType);
233	
234	const assertClaimItemsInsured = (steps: Step[]): void => {
235	  for (const claim of claimSteps(steps)) {
236	    const insuredCounts = countByType(policyQuoteFor(steps, claim)?.items ?? []);
237	    for (const [type, damageCount] of countDamagesByType(claim.incident.damages)) {
238	      if ((insuredCounts.get(type) ?? 0) < damageCount) {
239	        throw new Error(
240	          `damage references ${type} not insured by policy ${claim.policy}`,
241	        );
242	      }
243	    }
244	  }
245	};
246	
247	const assertNonNegativeDamages = (steps: Step[]): void => {
248	  for (const claim of claimSteps(steps)) {
249	    for (const damage of claim.incident.damages) {
250	      if (damage.amount < 0) {
251	        throw new Error(`negative damage amount: ${damage.amount}`);
252	      }
253	    }
254	  }
255	};
256	
257	const assertScenarioValid = (steps: Step[]): void => {
258	  assertKnownItemTypes(steps);
259	  assertClaimItemsInsured(steps);
260	  assertNonNegativeDamages(steps);
261	};
262	
263	export const processScenario = (scenario: Scenario): ScenarioResult => {
264	  assertScenarioValid(scenario.steps);
265	  const ledger = createPolicyLedger();
266	  const results = scenario.steps.map((step, index) =>
267	    step.op === "quote"
268	      ? handleQuote(step, index, scenario.customer, ledger)
269	      : handleClaim(step, ledger),
270	  );
271	  return { results };
272	};
